class Solution:
    def smallestString(self, s: str) -> str:
        s = list(s)
        i = 0
        # Skip all 'a's at the beginning
        while i < len(s) and s[i] == 'a':
            i += 1
        # If all characters are 'a', replace the last one with 'z'
        if i == len(s):
            s[-1] = 'z'
        else:
            # Replace characters until we hit 'a' or end of string
            while i < len(s) and s[i] != 'a':
                s[i] = chr(ord(s[i]) - 1)
                i += 1
        return ''.join(s)
